function deriveCurrentQuarter(cfg) {
  const today = Date.now();
  for (const q2 of cfg.quarters) {
    const start = new Date(q2.startDate).getTime();
    const end = new Date(q2.endDate).getTime();
    if (today >= start && today <= end) {
      const totalDays = Math.ceil((end - start) / 864e5);
      const elapsed = Math.ceil((today - start) / 864e5);
      const remaining = Math.max(0, totalDays - elapsed);
      return {
        quarterDef: q2,
        daysElapsed: elapsed,
        daysRemaining: remaining,
        progressPercent: Math.min(
          100,
          totalDays > 0 ? Math.round(elapsed / totalDays * 100) : 0
        )
      };
    }
  }
  return null;
}
